import React from 'react';
import Card from '../components/Card';
import FileImport from '../components/FileImport';
import ImportedDataTable from '../components/ImportedDataTable';


const BusinessData: React.FC = () => {

  return (
    <div className="max-w-full mx-auto px-4 sm:px-6 lg:px-32 py-8">
      <Card>
        <div className="py-8">
          <h1 className="text-2xl font-bold text-gray-900 mb-2 text-center">
            Business Data Management
          </h1>
          <p className="text-gray-600 mb-8 text-center">
            Analyze your business data. View imported data and reports below.
          </p>
          <ImportedDataTable />
        </div>
      </Card>
    </div>
  );
};

export default BusinessData;
